```typescript
// app/api/users/route.ts

import { NextResponse } from "next/server";
import { z } from "zod";

import { prisma } from "@rlm-saas/database";
import type { User } from "@prisma/client";

import { requireAuth } from "@/lib/auth";

/**
 * Query params validation schema
 */
const querySchema = z.object({
  limit: z
    .preprocess((v) => (v === undefined ? undefined : Number(v)), z
      .number()
      .int()
      .min(1)
      .max(100)
      .optional())
    .default(50),
  offset: z
    .preprocess((v) => (v === undefined ? undefined : Number(v)), z
      .number()
      .int()
      .min(0)
      .optional())
    .default(0),
  search: z.string().trim().optional(),
  sortBy: z.enum(["createdAt", "email", "name"]).optional().default("createdAt"),
  sortOrder: z.enum(["asc", "desc"]).optional().default("desc"),
  active: z
    .preprocess((v) => {
      if (v === "true") return true;
      if (v === "false") return false;
      return v;
    }, z.boolean().optional())
    .optional(),
});

type QueryParams = z.infer<typeof querySchema>;

function badRequest(body: unknown) {
  return NextResponse.json(body, { status: 400 });
}

function handleError(err: unknown) {
  if (err instanceof z.ZodError) {
    return badRequest({ success: false, error: "Invalid query parameters", details: err.flatten() });
  }
  // Generic error
  return NextResponse.json({ success: false, error: "Internal server error" }, { status: 500 });
}

export async function GET(request: Request): Promise<Response> {
  try {
    // 1) Authenticate
    const user = await requireAuth(); // throws if unauthenticated

    // 2) Parse & validate query params
    const url = new URL(request.url);
    const rawParams = Object.fromEntries(url.searchParams.entries());
    const params: QueryParams = querySchema.parse(rawParams);

    // 3) Build Prisma query
    const where: Record<string, unknown> = {};
    if (params.search) {
      where.OR = [
        { name: { contains: params.search, mode: "insensitive" } },
        { email: { contains: params.search, mode: "insensitive" } },
      ];
    }
    if (typeof params.active === "boolean") {
      where["isActive"] = params.active;
    }

    const orderBy = { [params.sortBy]: params.sortOrder };

    // 4) Delegate to DB
    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where,
        take: params.limit,
        skip: params.offset,
        orderBy,
        select: {
          id: true,
          name: true,
          email: true,
          isActive: true,
          createdAt: true,
          updatedAt: true,
        },
      }),
      prisma.user.count({ where }),
    ]);

    // 5) Return response
    return NextResponse.json({
      success: true,
      data: {
        users: users as User[],
        total,
        limit: params.limit,
        offset: params.offset,
      },
    });
  } catch (error: unknown) {
    return handleError(error);
  }
}
```

Notes:
- Validates limit, offset, search, sortBy, sortOrder, and active.
- Uses requireAuth() (per route handler pattern) — ensure "@/lib/auth" exports it.
- Uses prisma from "@rlm-saas/database". Adjust imports if your project uses a different prisma export.
- Returns a JSON object { success: true, data: { users, total, limit, offset } } and handles Zod validation errors with 400.

